local LxBaseState = require("LApp.component.fsm.LxBaseState")
---@class LCityPeopleFindPathState:LxBaseState 小人状态--待机
local LCityPeopleFindPathState = classX("LCityPeopleFindPathState", LxBaseState)

function LCityPeopleFindPathState:ctor()
    self.pathLineList = {};
    self.passPointList = {};
    self.beginWalk = false;
    --下一个要走的点
    self.nextPoint = nil;
    --目标点，暂为建筑位置
    self.targetPoint = nil;
    --当前的点
    self.curPoint = nil;
    self.lineEndPoint = nil;--路线上最后一个点
    self.moveSpeed = math.random(2.0,2.5);
    self.runToBuilding = false;--去建筑
    self.runToPatrol = false;--去巡逻
    self.patrolLint = 0;--巡逻路线
    self.runToPoint = false
    self._stateType = CityPeopleFsmState.FindPath;
    self._pathIndex = 0
    self._buildPoint = {34,35,36,37,38,39,40,41}
    self._randomPoint = {6,7,54,55,56,57}
end
function LCityPeopleFindPathState:Initialize()
    LxBaseState.Initialize(self)
    self._fsm = self:GetMachine();
    ---@type LCityPeopleUnit
    self._unit = self._fsm:GetVar("unit");
end
function LCityPeopleFindPathState:Execute(deltaTime)
    if (deltaTime == nil) then
        return
    end
    if (self.beginWalk) then
        if (self.runToBuilding) then
            self:RunBuildingFunc(deltaTime);
            return ;
        end
        if (self.runToPatrol) then
            self:RunPatrolFunc(deltaTime);
            return
        end
        if(self.runToPoint)then
            self:RunToPointFunc(deltaTime)
        end

    end
end
--去某个点
function LCityPeopleFindPathState:RunToPointFunc(deltaTime)
    if(self.targetPoint == nil)then
        return
    end
    if (Vector3.Distance(self._unit:GetPosition(), self.targetPoint) <= 0.05) then
        --结束
        self.beginWalk = false;
        self._fsm:ChangeState(CityPeopleFsmState.None)
        return
    end
    if(self.nextPoint == nil)then
        self.beginWalk = false;
        self._fsm:ChangeState(CityPeopleFsmState.None)
        return
    end
    if (Vector3.Distance(self._unit:GetPosition(), self.nextPoint) <= 0.05) then
        --走到一个点
        table.insert(self.passPointList, self.curPoint);
        self._pathIndex = self._pathIndex + 1;
        --self.nextPoint = self._unit.peopleMgr:GetNearestPoint(self.pathLineList, self.curPoint, self.passPointList, self.targetPoint);
        self.nextPoint = self._unit.peopleMgr:GetPointById(self.pathLineList[self._pathIndex])
        if (self.nextPoint == self.lineEndPoint or self.nextPoint == nil) then
            self.nextPoint = self.targetPoint;
        end
        self.curPoint = self.nextPoint;
        self:SetUnitDir()
        self:CheckCurLine()
    else
        self._unit:SetPosition(Vector3.MoveTowards(self._unit:GetPosition(), self.nextPoint, self.moveSpeed * deltaTime));
    end
end

--去建筑
function LCityPeopleFindPathState:RunBuildingFunc(deltaTime)
    if(self.targetPoint == nil)then
        return
    end

    if (Vector3.Distance(self._unit:GetPosition(), self.targetPoint) <= 0.05) then
        --结束
        self.beginWalk = false;
        if(self._unit._peopleBuilding == 2005 and self._timeState == 3)then
            --吃饭
            local eatNode =  self._unit._eatNode
            self._fsm:SetVar("targetPoint",eatNode.position)
        else
            self._fsm:SetVar("targetPoint",self._unit.peopleMgr:GetBuildPointById(self._gotoBuilding,self._unit._peopleRefId))
        end
        self:CheckCurLine()
        self._fsm:ChangeState(CityPeopleFsmState.GoToPoint)
        return
    end
    if(self.nextPoint == nil)then
        self.beginWalk = false;
        if(self._unit._peopleBuilding == 2005 and self._timeState == 3)then
            --吃饭
            local eatNode = self._unit._eatNode
            self._fsm:SetVar("targetPoint",eatNode.position)
        else
            self._fsm:SetVar("targetPoint",self._unit.peopleMgr:GetBuildPointById(self._gotoBuilding,self._unit._peopleRefId))
        end
        self:CheckCurLine()
        self._fsm:ChangeState(CityPeopleFsmState.GoToPoint)
        return
    end
    if (Vector3.Distance(self._unit:GetPosition(), self.nextPoint) <= 0.05) then
        --走到一个点
        table.insert(self.passPointList, self.curPoint);
        self._pathIndex = self._pathIndex + 1;
        self.nextPoint = self._unit.peopleMgr:GetPointById(self.pathLineList[self._pathIndex])
        if (self.nextPoint == self.lineEndPoint or self.nextPoint == nil) then
            self.nextPoint = self.targetPoint;
        end
        self.curPoint = self.nextPoint;
        self:CheckCurLine()
        self:SetUnitDir()
    else
        self._unit:SetPosition(Vector3.MoveTowards(self._unit:GetPosition(), self.nextPoint, self.moveSpeed * deltaTime));
    end
end
--去巡逻路线
function LCityPeopleFindPathState:RunPatrolFunc(deltaTime)
    if(self.targetPoint == nil)then
        return
    end
    if (Vector3.Distance(self._unit:GetPosition(), self.targetPoint) <= 0.05) then
        --结束
        self.beginWalk = false;
        --self._fsm:ChangeState(CityPeopleFsmState.None)
        self._unit:DoPatrol(false)
        self:CheckCurLine()
        return
    end
    if(self.nextPoint == nil)then
        self.beginWalk = false;
        self._unit:DoPatrol(false)
        self:CheckCurLine()
        return
    end
    if (Vector3.Distance(self._unit:GetPosition(), self.nextPoint) <= 0.05) then
        --走到一个点
        table.insert(self.passPointList, self.curPoint);
        self._pathIndex = self._pathIndex + 1;
        self.nextPoint = self._unit.peopleMgr:GetPointById(self.pathLineList[self._pathIndex])
        if (self.nextPoint == self.lineEndPoint or self.nextPoint == nil) then
            self.nextPoint = self.targetPoint;
        end
        self.curPoint = self.nextPoint;
        self:SetUnitDir()
        self:CheckCurLine()
    else
        self._unit:SetPosition(Vector3.MoveTowards(self._unit:GetPosition(), self.nextPoint, self.moveSpeed * deltaTime));
    end

end
function LCityPeopleFindPathState:CheckCurLine()
    local line = self.pathLineList[self._pathIndex]
    for i, v in pairs(self._buildPoint) do
        if(line == v)then
            self._unit:SetRenderOrder(10)
            return
        end
    end
    self._unit:SetDefaultRender()
end
function LCityPeopleFindPathState:SetUnitDir()
    if(self.nextPoint == nil or self.beginWalk == false)then
        return
    end
    local objPosition = self._unit:GetPosition()
    if(self.nextPoint.x < objPosition.x )then
        self._unit:SetDir(true)
        return
    end
    if(self.nextPoint.x > objPosition.x )then
        self._unit:SetDir(false)
        return
    end

end
function LCityPeopleFindPathState:GetPatrolRandom()
    return math.random(1,#self._randomPoint)
end
function LCityPeopleFindPathState:Enter()
    self:ClearParam()
    --开始检查参数
    local gotoBuilding = self._fsm:GetVar("GoToBuilding")
    local patrol = self._fsm:GetVar("Patrol")
    local gotoPoint = self._fsm:GetVar("GotoPoint")
    self._timeState = CtrlCenter.City:GetCurTimeState()
    if(self._unit.peopleMgr.findPathMgr == nil)then
        return
    end
    --self.patrolLint = patrol;
    if (gotoBuilding == nil and patrol == nil and gotoPoint == nil) then
        self._fsm:ChangeState(CityPeopleFsmState.Idle);
        return ;
    end
    self._unit:SetSpineAlpha(1);
    self._unit:PlayAni("run",true)
    if (gotoBuilding ~= nil) then
        --去某个建筑
        self._gotoBuilding = gotoBuilding
        --起始：从门口获取到哪个点最近，通过点判断在哪条路径上
        --结束：通过目标位置判断到哪个点最近，通过点判断在哪条路径
        --通过寻路算法，算出从起始路径到结束路径的过程
        --当走到结束路径的时候，判断结束路径里距离目标点最近的点
        --当走到结束路径上距离目标点最近的点时，直接走向目标点
        --应该一个点一个点的走，开始点是第一个，同时把开始点放入列表，然后走向路径中距离最近的点，走到之后把这个点也放到列表，然后以这个点为开始点，走向列表外下一个距离最近的点，直到结束
        local startPoint = self._unit:GetPosition()
        local startLine = self._unit.peopleMgr:GetPointNearestLine(startPoint)
        self.targetPoint = self._unit.peopleMgr:GetBuildPositionById(gotoBuilding,self._unit._peopleRefId);
        local endLine = self._unit.peopleMgr:GetPointNearestLine(self.targetPoint)
        self._unit.peopleMgr.findPathMgr:FindPath(startLine, endLine, function(pathList)

            self.pathLineList = pathList;

            self.curPoint = startPoint;
            table.insert(self.passPointList, startPoint);

            self._pathIndex = self._pathIndex + 1;
            self.nextPoint = self._unit.peopleMgr:GetPointById(self.pathLineList[self._pathIndex])
            self.lineEndPoint =  self.targetPoint
            self.runToPatrol = false;
            self.runToBuilding = true;
            self.runToPoint = false
            self.beginWalk = true;
            self:SetUnitDir()
        end)
        return
    end
    if (patrol == true) then
        --巡逻

        --当前位置为起点
        --找到距离当前位置最近的路线
        local startPoint = self._unit:GetPosition()
        local startLine = self._unit.peopleMgr:GetPointNearestLine(startPoint)
        local endLine = self:GetPatrolRandom()
        self._unit.peopleMgr.findPathMgr:FindPath(startLine, endLine, function(pathList)

            self.pathLineList = pathList;
            self.curPoint = startPoint;
            table.insert(self.passPointList, startPoint);
            --local targetLinePoint = self._unit.peopleMgr.mainPoint[patrol];
            self._pathIndex = self._pathIndex + 1
            self.targetPoint = self._unit.peopleMgr:GetPointById(self.pathLineList[#self.pathLineList]);
            self.nextPoint = self._unit.peopleMgr:GetPointById(self.pathLineList[self._pathIndex]);
            self.lineEndPoint = self.targetPoint
            self.runToPatrol = true;
            self.runToBuilding = false;
            self.runToPoint = false
            self.beginWalk = true;
            self:SetUnitDir()
        end)
        return
    end
    if(gotoPoint ~= nil)then
        --跟去建筑差不多

        local startPoint = self._unit:GetPosition()
        local startLine = self._unit.peopleMgr:GetPointNearestLine(startPoint)
        self.targetPoint = gotoPoint
        local endLine = self._unit.peopleMgr:GetPointNearestLine(self.targetPoint)
        if(self._unit._peopleBuilding == 2005)then
            self.curPoint = startPoint;
            self.nextPoint = self.targetPoint
            self.lineEndPoint =  self.targetPoint
            self.runToPatrol = false;
            self.runToBuilding = false;
            self.runToPoint = true
            self.beginWalk = true;
            self:SetUnitDir()
            return
            --print("餐厅")
            --for i, v in pairs(pathList) do
            --    print(v)
            --end
            --print("gotoPointEnd")
        end
        self._unit.peopleMgr.findPathMgr:FindPath(startLine, endLine, function(pathList)
            self.pathLineList = pathList;
            --if(self._unit._peopleBuilding == 2005)then
            --    print("餐厅")
            --    for i, v in pairs(pathList) do
            --        print(v)
            --    end
            --    print("gotoPointEnd")
            --end


            self.curPoint = startPoint;
            table.insert(self.passPointList, startPoint);
            self._pathIndex = self._pathIndex + 1;
            self.nextPoint = self._unit.peopleMgr:GetPointById(self.pathLineList[self._pathIndex])
            self.lineEndPoint =  self.targetPoint
            self.runToPatrol = false;
            self.runToBuilding = false;
            self.runToPoint = true
            self.beginWalk = true;
            self:SetUnitDir()
        end)
    end
end

function LCityPeopleFindPathState:ClearParam()
    if(self.pathLineList)then
        table.dispose(self.pathLineList)
    end
    if(self._randomPoint)then
        table.dispose(self._randomPoint)
    end
    table.dispose(self.passPointList)
    self._pathIndex = 0
    self.beginWalk = false
    self.nextPoint = nil
    self.targetPoint = nil
    self.targetPoint = nil
    self.lineEndPoint = nil
    self.runToBuilding = false
    self.runToPatrol = false
    self.runToPoint = false
    self.patrolLint = 0
end

function LCityPeopleFindPathState:Exit()
    --self:ClearParam()
    --self._fsm:RemoveVar("Patrol");--巡逻，value为巡逻路线
    --self._fsm:RemoveVar("GoToBuilding");--去某个建筑，value为具体建筑

end

function LCityPeopleFindPathState:Dispose()
    self:ClearParam()
    LxBaseState.Dispose(self)
end
return LCityPeopleFindPathState